}

static bool read(){
In in;
N=in.ni();
M=in.ni();
if(N<=0||M<=0)return false;
Orig.v.resize(N);
Orig.f.resize(M);
bminv={
1e100,1e100,1e100}
;
bmaxv={
-1e100,-1e100,-1e100}
;
for(int i=0;
i<N;
i++){
char c=in.nc();
if(c!='v'&&c!='V')--in.p;
V p{
in.nd(),in.nd(),in.nd()}
;
Orig.v[i]=p;
bminv.x=min(bminv.x,p.x);
bminv.y=min(bminv.y,p.y);
bminv.z=min(bminv.z,p.z);
bmaxv.x=max(bmaxv.x,p.x);
bmaxv.y=max(bmaxv.y,p.y);
bmaxv.z=max(bmaxv.z,p.z);
}
for(int i=0;
i<M;
i++){
char c=in.nc();
if(c!='f'&&c!='F')--in.p;
Orig.f[i]={
in.ni()-1,in.ni()-1,in.ni()-1}
;
}
diagv=norm(bmaxv-bminv);
if(!(diagv>0))diagv=1;
ctr=(bminv+bmaxv)*0.5;
tau=0.05*diagv*0.996;
tau2=tau*tau;
return true;
}

static bool valid(const Mesh&m){
int n=m.v.size();
if(n<=0||m.f.empty()||n>N)return false;
